        for d in data:
            samples = " | ".join(d["unique_values"][:3])
            w.writerow([d["key"], d["count"], d["is_constant"], d["value_type"], samples])
    print("Created survey_results.csv (human readable!)")
except Exception as e:
    print("Could not parse survey_results.json:", e)

# Summarize dry run removals
try:
    removals = {}
    with open("dry_run_detail.jsonl", "r") as f:
        for line in f:
            j = json.loads(line)
            for tier in ["tier1_junk_removed", "tier3_redundant_removed", "tier4_noise_removed"]:
                for tag in j.get(tier, {}):
                    removals[tag] = removals.get(tag, 0) + 1

    with open("dry_run_removed_tags.csv", "w", newline="") as f:
        w = csv.writer(f)
        w.writerow(["Removed Tag", "Files Affected"])
        for tag, count in sorted(removals.items(), key=lambda x: -x[1]):
            w.writerow([tag, count])
    print("Created dry_run_removed_tags.csv (aggregating the dry_run_detail.jsonl!)")
except Exception as e:
    print("Could not aggregate dry run details:", e)
